Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  if (std::is_same_v<T, Student>) {
    auto write_op = sqlgen::write(conn, records);
    write_op.value();
  } else if (std::is_same_v<T, Course>) {
    auto write_op = sqlgen::write(conn, records);
    write_op.value();
  } else if (std::is_same_v<T, Score>) {
    auto write_op = sqlgen::write(conn, records);
    write_op.value();
  } else if (std::is_same_v<T, Major>) {
    auto write_op = sqlgen::write(conn, records);
    write_op.value();
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  sqlgen::dynamic::DeleteFrom delete_stmt;
  delete_stmt.table = table_name;

  // Determine the correct column name for the primary key
  if (table_name == "Student") {
    delete_stmt.where = sqlgen::dynamic::Condition{
      .val = sqlgen::dynamic::BinaryOp{
        .left = sqlgen::dynamic::Column{"SNo"},
        .op = "==",
        .right = sqlgen::dynamic::Value{record_id}
      }
    };
  } else if (table_name == "Course") {
    delete_stmt.where = sqlgen::dynamic::Condition{
      .val = sqlgen::dynamic::BinaryOp{
        .left = sqlgen::dynamic::Column{"CID"},
        .op = "==",
        .right = sqlgen::dynamic::Value{record_id}
      }
    };
  } else if (table_name == "Score") {
    delete_stmt.where = sqlgen::dynamic::Condition{
      .val = sqlgen::dynamic::BinaryOp{
        .left = sqlgen::dynamic::Column{"ScID"},
        .op = "==",
        .right = sqlgen::dynamic::Value{record_id}
      }
    };
  } else if (table_name == "Major") {
    delete_stmt.where = sqlgen::dynamic::Condition{
      .val = sqlgen::dynamic::BinaryOp{
        .left = sqlgen::dynamic::Column{"MID"},
        .op = "==",
        .right = sqlgen::dynamic::Value{record_id}
      }
    };
  }

  sqlgen::delete_from_impl(conn, delete_stmt).value();
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  sqlgen::dynamic::Update update_stmt;
  update_stmt.table = table_name;

  // Build SET clause
  update_stmt.set = sqlgen::dynamic::Set{
    .column = col_name,
    .to = new_value
  };

  // Build WHERE clause
  update_stmt.where = sqlgen::dynamic::Condition{
    .val = sqlgen::dynamic::BinaryOp{
      .left = sqlgen::dynamic::Column{col_name == "SNo" ? "SNo" : 
                                      col_name == "CID" ? "CID" : 
                                      col_name == "ScID" ? "ScID" : 
                                      col_name == "MID" ? "MID" : ""},
      .op = "==",
      .right = sqlgen::dynamic::Value{record_id}
    }
  };

  sqlgen::update_impl(conn, update_stmt).value();
}
```

**Explanation:**

1. **add_eas_records**: Uses `sqlgen::write` to insert records into the specified table. The template parameter `T` determines which table structure to use (Student, Course, Score, or Major).

2. **delete_eas_records_by_id**: Constructs a DELETE statement using `sqlgen::dynamic::DeleteFrom` with a WHERE clause that matches the primary key ID. The primary key column name is determined based on the table type.

3. **modify_eas_records_by_id**: Constructs an UPDATE statement using `sqlgen::dynamic::Update` that sets the specified column to the new value, with a WHERE clause matching the primary key ID.

All functions use the `sqlgen::sqlite::connect` to establish a connection to the database at `data/eas_database.db` and handle errors using `.value()` for simplicity. The implementation follows the sqlgen library patterns shown in the reference materials.

