#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    int32_t Sex;
    std::optional<std::chrono::system_clock::time_point> Birthday;
    std::optional<int32_t> Major;
    float Scorses;
    std::optional<std::string> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<uint32_t> CID;
    std::string CName;
    std::optional<int32_t> Term = 1;
    std::optional<int32_t> CTime;
    float Credit;
  };

  struct Score {
    sqlgen::ForeignKey<std::string, Student> SNo;
    sqlgen::ForeignKey<uint32_t, Course> CID;
    std::optional<float> Score;
  };

  void design_eas_database() {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

    // Create tables in the correct order (foreign keys depend on referenced tables)
    conn_result.and_then([](const auto& conn) {
      return sqlgen::create_table<Student>()(conn);
    }).and_then([](const auto& conn) {
      return sqlgen::create_table<Course>()(conn);
    }).and_then([](const auto& conn) {
      return sqlgen::create_table<Score>()(conn);
    });
  }

}
```

