std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // 2. Create User and Post tables
    auto create_user_table = sqlgen::create_table<User>();
    auto create_post_table = sqlgen::create_table<Post>();

    conn->execute(create_user_table.to_sql());
    conn->execute(create_post_table.to_sql());

    // 3. Build and execute the query
    auto query = sqlgen::select_from<User, "u">("user_id"_c, "username"_c)
        | sqlgen::inner_join<Post, "p">("u"_c("user_id") == "p"_c("user_id"))
        | sqlgen::where("p"_c("created_at") >= sqlgen::DateTime("2025-12-01") && 
                       "p"_c("created_at") <= sqlgen::DateTime("2025-12-31"))
        | sqlgen::to<std::vector<ActiveUser>>;

    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query failed");
    }

    return result.value();
}

}  // namespace query_active_users_posts
