std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // Start with base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Build WHERE conditions dynamically
    auto where_conditions = sqlgen::where();

    // Title keyword filter with LIKE
    if (filters.title_keyword) {
        where_conditions = where_conditions && ("title"_c.like("%" + *filters.title_keyword + "%"));
    }

    // Minimum year filter
    if (filters.min_year) {
        where_conditions = where_conditions && ("year"_c >= *filters.min_year);
    }

    // Genre filter
    if (filters.genre) {
        where_conditions = where_conditions && ("genre"_c == *filters.genre);
    }

    // Maximum price filter
    if (filters.max_price) {
        where_conditions = where_conditions && ("price"_c <= *filters.max_price);
    }

    // Apply WHERE clause if any conditions were added
    if (where_conditions) {
        query = query | where_conditions;
    }

    // Execute the query and return results
