```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  try {
    // Read sender account with where condition
    auto read_sender = sqlgen::read<std::optional<Account>> 
                     | sqlgen::where("account_id"_c == from_account_id);
    auto sender_result = read_sender(conn);
    if (!sender_result) {
      conn->rollback();
      return false;
    }

    auto sender = sender_result.value();
    if (!sender || sender->balance < amount) {
      conn->rollback();
      return false;
    }

    // Update sender account: balance = balance - amount
    auto update_sender = sqlgen::update<Account>("balance"_c.set("balance"_c - amount))
                       | sqlgen::where("account_id"_c == from_account_id);
    auto update_sender_result = update_sender(conn);
    if (!update_sender_result) {
      conn->rollback();
      return false;
    }

    // Update receiver account: balance = balance + amount
    auto update_receiver = sqlgen::update<Account>("balance"_c.set("balance"_c + amount))
                           | sqlgen::where("account_id"_c == to_account_id);
    auto update_receiver_result = update_receiver(conn);
    if (!update_receiver_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the SQLite database.

2. **Transaction Management**: 
   - Begins transaction with `conn->begin_transaction()`
   - Commits with `conn->commit()`
   - Rolls back on any failure with `conn->rollback()`

3. **Read Operation**: Uses `sqlgen::read<std::optional<Account>>` with where condition to check if sender account exists and has sufficient balance.

4. **Update Operations**:
   - First update subtracts amount from sender's balance
   - Second update adds amount to receiver's balance
   - Both use the `set` method with column arithmetic operations

5. **Error Handling**: Comprehensive error checking at each step with proper rollback on failures.

6. **Column Literals**: Uses `"account_id"_c` and `"balance"_c` column literals for type-safe column references.

This implementation follows the sqlgen principles and uses the provided functions and data types correctly to achieve the required functionality.

