#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Construct the SELECT query for the view
  auto query = select_from<Sale>(
      "name"_c.as<"product_name">(),
      sum("quantity"_c).as<"total_quantity">(),
      sum("amount"_c).as<"total_revenue">()
  ) | group_by("name"_c);

  // Create the view definition
  auto create_view_obj = create_as<SalesSummary>(query) | if_not_exists;

  // Execute the view creation
  auto result = create_view_obj(conn);
  return result;
}

}  // namespace schema_create_view_sales_summary
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **SELECT Query Construction**: 
   - Uses `select_from<Sale>` with column selection
   - Applies `sum()` aggregation functions for quantity and amount
   - Uses `as<"alias">()` to rename columns
   - Applies `group_by("name"_c)` for grouping
3. **View Creation**:
   - Uses `create_as<SalesSummary>(query)` to define the view
   - Applies `if_not_exists` modifier using `operator|`
4. **Execution**: Calls the created view object with the connection to execute
5. **Error Handling**: Checks connection result and returns boolean status

The implementation follows sqlgen's fluent API pattern and correctly handles the aggregation logic required for the SalesSummary view.

